 document.addEventListener('DOMContentLoaded',()=>{const menuToggle=document.getElementById('menuToggle');const navLinks=document.getElementById('navLinks');if(menuToggle && navLinks){menuToggle.addEventListener('click',()=>{navLinks.classList.toggle('active');const icon=menuToggle.querySelector('i');if(icon){icon.classList.toggle('fa-bars');icon.classList.toggle('fa-times');}});navLinks.querySelectorAll('a').forEach(link=>{link.addEventListener('click',(e)=>{if(!link.parentElement.classList.contains('nav-dropdown')){navLinks.classList.remove('active');const icon=menuToggle.querySelector('i');if(icon){icon.classList.add('fa-bars');icon.classList.remove('fa-times');}}});});}const navbar=document.getElementById('navbar');if(navbar){window.addEventListener('scroll',()=>{if(window.scrollY > 50)navbar.classList.add('scrolled');else navbar.classList.remove('scrolled');});}document.querySelectorAll('.faq-item').forEach(item=>{const q=item.querySelector('.faq-question');if(q)q.addEventListener('click',()=> item.classList.toggle('active'));});const observer=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.style.opacity='1';entry.target.style.transform='translateY(0)';}});},{threshold: 0.1});document.querySelectorAll('.service-card, .project-card, .card, .stat-card, .faq-item, .timeline-item').forEach(el=>{el.style.opacity='0';el.style.transform='translateY(30px)';el.style.transition='opacity 0.6s ease, transform 0.6s ease';observer.observe(el);});document.querySelectorAll('[data-counter]').forEach(el=>{const target=parseInt(el.dataset.counter);const duration=2000;let started=false;const startCounter=()=>{if(started)return;started=true;let current=0;const step=target /(duration / 16);const update=()=>{current +=step;if(current >=target){el.textContent=target +(el.dataset.suffix || '');}else{el.textContent=Math.floor(current)+(el.dataset.suffix || '');requestAnimationFrame(update);}};update();};const obs=new IntersectionObserver((entries)=>{entries.forEach(e=>{if(e.isIntersecting)startCounter();});},{threshold: 0.5});obs.observe(el);});initConfigurator();});function initConfigurator(){const config={buildingType: 'villa', area: 200, fire: false, security: false, cameras: false, automation: false, solar: false, maintenance: 'none'};const prices={buildingType:{villa: 1.0, apartment: 0.7, shop: 0.85, factory: 1.4}, fire:{base: 1500, perM2: 5}, security:{base: 1200, perM2: 4}, cameras:{base: 800, perCamera: 350}, automation:{base: 2000, perRoom: 400}, solar:{base: 3000, perKw: 1500}, maintenance:{monthly: 200, quarterly: 600}};const cameraCount=document.getElementById('cameraCount');const roomCount=document.getElementById('roomCount');const solarKw=document.getElementById('solarKw');document.querySelectorAll('[data-building]').forEach(chip=>{chip.addEventListener('click',()=>{document.querySelectorAll('[data-building]').forEach(c=> c.classList.remove('active'));chip.classList.add('active');config.buildingType=chip.dataset.building;updateSummary();});});['fire', 'security', 'cameras', 'automation', 'solar'].forEach(service=>{document.querySelectorAll(`[data-service="${service}"]`).forEach(chip=>{chip.addEventListener('click',()=>{config[service]=!config[service];chip.classList.toggle('active');const extra=document.getElementById(`${service}-extra`);if(extra)extra.style.display=config[service]? 'block' : 'none';updateSummary();});});});document.querySelectorAll('[data-maintenance]').forEach(chip=>{chip.addEventListener('click',()=>{document.querySelectorAll('[data-maintenance]').forEach(c=> c.classList.remove('active'));chip.classList.add('active');config.maintenance=chip.dataset.maintenance;updateSummary();});});document.querySelectorAll('.config-input').forEach(input=>{input.addEventListener('input',()=>{const key=input.dataset.key;const value=parseFloat(input.value)|| 0;config[key]=value;updateSummary();});});function calculate(){const buildingMultiplier=prices.buildingType[config.buildingType]|| 1;const areaCost=config.area * 2 * buildingMultiplier;let total=areaCost;if(config.fire)total +=prices.fire.base +(config.area * prices.fire.perM2);if(config.security)total +=prices.security.base +(config.area * prices.security.perM2);if(config.cameras)total +=prices.cameras.base +((cameraCount?.value || 4)* prices.cameras.perCamera);if(config.automation)total +=prices.automation.base +((roomCount?.value || 4)* prices.automation.perRoom);if(config.solar)total +=prices.solar.base +((solarKw?.value || 3)* prices.solar.perKw);if(config.maintenance==='monthly')total +=prices.maintenance.monthly;if(config.maintenance==='quarterly')total +=prices.maintenance.quarterly;return Math.round(total);}function updateSummary(){const total=calculate();const totalEl=document.getElementById('configTotal');if(totalEl)totalEl.textContent=total.toLocaleString()+ ' ₪';const rows=document.getElementById('configSummaryRows');if(rows){rows.innerHTML='';rows.innerHTML +=`<div class="summary-row"><span class="summary-label">نوع المبنى</span><span class="summary-value">${getBuildingLabel(config.buildingType)}</span></div>`;rows.innerHTML +=`<div class="summary-row"><span class="summary-label">المساحة</span><span class="summary-value">${config.area}م²</span></div>`;if(config.fire)rows.innerHTML +=`<div class="summary-row"><span class="summary-label">إنذار حريق</span><span class="summary-value">✓ مضاف</span></div>`;if(config.security)rows.innerHTML +=`<div class="summary-row"><span class="summary-label">إنذار سرقة</span><span class="summary-value">✓ مضاف</span></div>`;if(config.cameras)rows.innerHTML +=`<div class="summary-row"><span class="summary-label">كاميرات(${cameraCount?.value || 4})</span><span class="summary-value">✓ مضاف</span></div>`;if(config.automation)rows.innerHTML +=`<div class="summary-row"><span class="summary-label">أتمتة(${roomCount?.value || 4}غرف)</span><span class="summary-value">✓ مضاف</span></div>`;if(config.solar)rows.innerHTML +=`<div class="summary-row"><span class="summary-label">طاقة شمسية(${solarKw?.value || 3}kW)</span><span class="summary-value">✓ مضاف</span></div>`;if(config.maintenance !=='none')rows.innerHTML +=`<div class="summary-row"><span class="summary-label">صيانة ${config.maintenance==='monthly' ? 'شهرية' : 'ربعية'}</span><span class="summary-value">✓ مضاف</span></div>`;}}function getBuildingLabel(type){return{villa: 'فيلا', apartment: 'شقة', shop: 'محل تجاري', factory: 'مصنع'}[type]|| type;}if(document.getElementById('configTotal'))updateSummary();}document.addEventListener('submit',(e)=>{if(e.target.matches('.contact-form')|| e.target.matches('#contactForm')){const btn=e.target.querySelector('.form-submit');if(btn){btn.innerHTML='<i class="fas fa-spinner fa-spin"></i> جاري الإرسال...';btn.disabled=true;}}});function portalLogin(e){e.preventDefault();const btn=e.target.querySelector('button[type="submit"]');if(btn){btn.innerHTML='<i class="fas fa-spinner fa-spin"></i> جاري التحقق...';btn.disabled=true;setTimeout(()=>{window.location.href='dashboard.html';}, 1500);}}